mapper.select:
SELECT * FROM ( SELECT '-1' AS PARENT_GROUP_ID, 'ROOT' AS GROUP_ID, '코드그룹 모음' AS GROUP_NAME, '수정할 수 없습니다.' AS REMARK, 1 AS LOAD_ON_DEMAND, '' AS HOMEPAGE_YN FROM DUAL UNION ALL SELECT 'ROOT' AS PARENT_GROUP_ID, GROUP_ID, GROUP_NAME || '(' || GROUP_ID || ')' AS GROUP_NAME, REMARK, 0 AS LOAD_ON_DEMAND, HOMEPAGE_YN FROM CMS_CODE_GROUP WHERE 1 = 1
AND HOMEPAGE_ID = #{homepage_id}
AND HOMEPAGE_ID = 'CMS'
) CONNECT BY PRIOR GROUP_ID = PARENT_GROUP_ID START WITH GROUP_ID = 'ROOT' ORDER SIBLINGS BY GROUP_ID

SELECT GROUP_ID, GROUP_NAME, REMARK, HOMEPAGE_YN FROM ( SELECT '00000' as group_id, '홈페이지리스트' as group_name,'없는 코드이지만 홈페이지 리스트를 코드처럼 사용하기 위해 등록' as remark,'Y' as homepage_yn FROM DUAL UNION ALL SELECT GROUP_ID, GROUP_NAME, REMARK, HOMEPAGE_YN FROM CMS_CODE_GROUP
WHERE HOMEPAGE_ID = #{homepage_id}
) ORDER BY GROUP_ID

